{"path": "/tmp/sv-9c4919a59bf04d81b465324db53e24bc/SiteInspector/SiteInspector.Client/Services/LocalStorageService.cs", "file_text": "using System.Text.Json;
using Microsoft.JSInterop;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class LocalStorageService : IAsyncDisposable
{
    private readonly IJSRuntime _js;
    private IJSObjectReference? _module;
    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase
    };

    public LocalStorageService(IJSRuntime js)
    {
        _js = js;
    }

    private async Task<IJSObjectReference> GetModuleAsync()
    {
        _module ??= await _js.InvokeAsync<IJSObjectReference>("import", "./js/indexedDb.js");
        return _module;
    }

    public async Task SaveSiteAsync(ConstructionSite site)
    {
        var module = await GetModuleAsync();
        var json = JsonSerializer.Serialize(site, JsonOptions);
        var element = JsonSerializer.Deserialize<object>(json, JsonOptions);
        await module.InvokeVoidAsync("setItem", "sites", element);
    }

    public async Task<List<ConstructionSite>> GetAllSitesAsync()
    {
        var module = await GetModuleAsync();
        return await module.InvokeAsync<List<ConstructionSite>>("getAllItems", "sites");
    }

    public async Task<ConstructionSite?> GetSiteAsync(string id)
    {
        var module = await GetModuleAsync();
        return await module.InvokeAsync<ConstructionSite?>("getItem", "sites", id);
    }

    public async Task SaveInspectionAsync(Inspection inspection)
    {
        var module = await GetModuleAsync();
        var json = JsonSerializer.Serialize(inspection, JsonOptions);
        var element = JsonSerializer.Deserialize<object>(json, JsonOptions);
        await module.InvokeVoidAsync("setItem", "inspections", element);
    }

    public async Task<List<Inspection>> GetAllInspectionsAsync()
    {
        var module = await GetModuleAsync();
        return await module.InvokeAsync<List<Inspection>>("getAllItems", "inspections");
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        var module = await GetModuleAsync();
        return await module.InvokeAsync<Inspection?>("getItem", "inspections", id);
    }

    public async Task<List<Inspection>> GetInspectionsForSiteAsync(string siteId)
    {
        var module = await GetModuleAsync();
        return await module.InvokeAsync<List<Inspection>>("getItemsByIndex", "inspections", "siteId", siteId);
    }

    public async Task<List<Inspection>> GetUnsyncedInspectionsAsync()
    {
        var module = await GetModuleAsync();
        return await module.InvokeAsync<List<Inspection>>("getItemsByIndex", "inspections", "isSynced", false);
    }

    public async Task DeleteInspectionAsync(string id)
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync("deleteItem", "inspections", id);
    }

    public async Task<bool> IsOnlineAsync()
    {
        var module = await GetModuleAsync();
        return await module.InvokeAsync<bool>("isOnline");
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            await _module.DisposeAsync();
        }
    }
}
"}

{"path": "/tmp/sv-9c4919a59bf04d81b465324db53e24bc/SiteInspector/SiteInspector.Client/Services/SyncService.cs", "file_text": "using System.Net.Http.Json;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class SyncService
{
    private readonly LocalStorageService _localStorage;
    private readonly HttpClient _http;
    private bool _isSyncing;

    public event Action<string>? OnSyncStatusChanged;

    public SyncService(LocalStorageService localStorage, HttpClient http)
    {
        _localStorage = localStorage;
        _http = http;
    }

    public async Task TrySyncAsync()
    {
        if (_isSyncing) return;

        try
        {
            if (!await _localStorage.IsOnlineAsync())
            {
                OnSyncStatusChanged?.Invoke("Offline");
                return;
            }

            _isSyncing = true;
            OnSyncStatusChanged?.Invoke("Syncing...");

            var unsynced = await _localStorage.GetUnsyncedInspectionsAsync();
            var syncedCount = 0;

            foreach (var inspection in unsynced)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("api/inspections", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        inspection.IsSynced = true;
                        await _localStorage.SaveInspectionAsync(inspection);
                        syncedCount++;
                    }
                }
                catch
                {
                    // Server unavailable — will retry next sync
                }
            }

            OnSyncStatusChanged?.Invoke(syncedCount > 0 ? $"Synced {syncedCount} inspection(s)" : "Up to date");
        }
        catch
        {
            OnSyncStatusChanged?.Invoke("Sync failed");
        }
        finally
        {
            _isSyncing = false;
        }
    }
}
"}

