@page "/"
@inject LocalStorageService Storage
@inject NavigationManager Nav

<PageTitle>Site Inspector</PageTitle>

<div class="page-header">
    <h1>🏗️ Sites</h1>
    <button class="btn btn-primary btn-lg" @onclick="ShowAddSite">+ Add Site</button>
</div>

@if (_showAddForm)
{
    <div class="card add-form">
        <div class="card-body">
            <input class="form-control form-control-lg mb-2" @bind="_newSiteName" placeholder="Site name" />
            <input class="form-control form-control-lg mb-2" @bind="_newSiteAddress" placeholder="Address" />
            <div class="d-flex gap-2">
                <button class="btn btn-success btn-lg flex-fill" @onclick="AddSite">Save</button>
                <button class="btn btn-secondary btn-lg" @onclick="() => _showAddForm = false">Cancel</button>
            </div>
        </div>
    </div>
}

@if (_sites is null)
{
    <p class="loading">Loading sites...</p>
}
else if (_sites.Count == 0)
{
    <div class="empty-state">
        <p>No construction sites yet.</p>
        <p>Tap <strong>+ Add Site</strong> to get started.</p>
    </div>
}
else
{
    <div class="site-list">
        @foreach (var site in _sites.OrderByDescending(s => s.CreatedAt))
        {
            <div class="site-card" @onclick="() => Nav.NavigateTo($&quot;site/{site.Id}&quot;)">
                <div class="site-name">@site.Name</div>
                <div class="site-address">@site.Address</div>
            </div>
        }
    </div>
}

@code {
    private List<ConstructionSite>? _sites;
    private bool _showAddForm;
    private string _newSiteName = "";
    private string _newSiteAddress = "";

    protected override async Task OnInitializedAsync()
    {
        _sites = await Storage.GetAllSitesAsync();
    }

    private void ShowAddSite()
    {
        _showAddForm = true;
        _newSiteName = "";
        _newSiteAddress = "";
    }

    private async Task AddSite()
    {
        if (string.IsNullOrWhiteSpace(_newSiteName)) return;

        var site = new ConstructionSite
        {
            Name = _newSiteName.Trim(),
            Address = _newSiteAddress.Trim()
        };

        await Storage.SaveSiteAsync(site);
        _sites ??= new();
        _sites.Add(site);
        _showAddForm = false;
    }
}

@page "/site/{SiteId}"
@inject LocalStorageService Storage
@inject NavigationManager Nav

<PageTitle>@(_site?.Name ?? "Site")</PageTitle>

<div class="page-header">
    <button class="btn btn-outline-secondary" @onclick="() => Nav.NavigateTo(&quot;/&quot;)">← Back</button>
    <h1>@(_site?.Name ?? "...")</h1>
</div>

@if (_site is not null)
{
    <p class="site-address-detail">@_site.Address</p>

    <button class="btn btn-primary btn-lg w-100 mb-3" @onclick="StartNewInspection">
        📋 New Inspection
    </button>

    <h2>Past Inspections</h2>

    @if (_inspections.Count == 0)
    {
        <p class="text-muted">No inspections yet for this site.</p>
    }
    else
    {
        <div class="inspection-list">
            @foreach (var insp in _inspections.OrderByDescending(i => i.InspectionDate))
            {
                <div class="inspection-card" @onclick="() => Nav.NavigateTo($&quot;inspection/{insp.Id}&quot;)">
                    <div class="inspection-date">@insp.InspectionDate.ToLocalTime().ToString("MMM dd, yyyy h:mm tt")</div>
                    <div class="inspection-meta">
                        <span class="badge @(insp.Status == InspectionStatus.Completed ? "bg-success" : "bg-warning")">
                            @insp.Status
                        </span>
                        <span class="badge @(insp.IsSynced ? "bg-info" : "bg-secondary")">
                            @(insp.IsSynced ? "Synced" : "Local")
                        </span>
                        <span>@insp.ChecklistItems.Count(c => c.Result != CheckResult.NotChecked)/@insp.ChecklistItems.Count checked</span>
                    </div>
                </div>
            }
        </div>
    }
}

@code {
    [Parameter] public string SiteId { get; set; } = "";

    private ConstructionSite? _site;
    private List<Inspection> _inspections = new();

    protected override async Task OnInitializedAsync()
    {
        _site = await Storage.GetSiteAsync(SiteId);
        _inspections = await Storage.GetInspectionsForSiteAsync(SiteId);
    }

    private async Task StartNewInspection()
    {
        var inspection = new Inspection
        {
            SiteId = SiteId,
            SiteName = _site?.Name ?? "",
            ChecklistItems = ChecklistTemplateService.GetDefaultChecklist()
        };

        await Storage.SaveInspectionAsync(inspection);
        Nav.NavigateTo($"inspection/{inspection.Id}");
    }
}

@page "/inspection/{InspectionId}"
@inject LocalStorageService Storage
@inject NavigationManager Nav
@inject SyncService Sync

<PageTitle>Inspection</PageTitle>

@if (_inspection is null)
{
    <p class="loading">Loading...</p>
}
else
{
    <div class="page-header">
        <button class="btn btn-outline-secondary" @onclick="GoBack">← Back</button>
        <h1>Inspection</h1>
    </div>

    <div class="inspection-tabs">
        <button class="tab-btn @(_activeTab == "checklist" ? "active" : "")" @onclick="() => _activeTab = &quot;checklist&quot;">
            ✓ Checklist
        </button>
        <button class="tab-btn @(_activeTab == "photos" ? "active" : "")" @onclick="() => _activeTab = &quot;photos&quot;">
            📷 Photos (@_inspection.Photos.Count)
        </button>
        <button class="tab-btn @(_activeTab == "notes" ? "active" : "")" @onclick="() => _activeTab = &quot;notes&quot;">
            📝 Notes
        </button>
    </div>

    @if (_activeTab == "checklist")
    {
        <div class="checklist">
            @foreach (var category in _inspection.ChecklistItems.GroupBy(c => c.Category))
            {
                <h3 class="checklist-category">@category.Key</h3>
                @foreach (var item in category)
                {
                    <div class="checklist-item @GetItemClass(item)">
                        <div class="checklist-desc">@item.Description</div>
                        <div class="checklist-actions">
                            <button class="check-btn pass @(item.Result == CheckResult.Pass ? "selected" : "")"
                                    @onclick="() => SetResult(item, CheckResult.Pass)">✓</button>
                            <button class="check-btn fail @(item.Result == CheckResult.Fail ? "selected" : "")"
                                    @onclick="() => SetResult(item, CheckResult.Fail)">✗</button>
                            <button class="check-btn na @(item.Result == CheckResult.NotApplicable ? "selected" : "")"
                                    @onclick="() => SetResult(item, CheckResult.NotApplicable)">N/A</button>
                        </div>
                    </div>
                }
            }
        </div>
    }
    else if (_activeTab == "photos")
    {
        <div class="photo-section">
            <label class="btn btn-primary btn-lg w-100 mb-3">
                📸 Take / Attach Photo
                <InputFile OnChange="OnPhotoSelected" accept="image/*" capture="environment" style="display:none" />
            </label>

            @if (_inspection.Photos.Count == 0)
            {
                <p class="text-muted">No photos attached yet.</p>
