</div>

@if (_showAddForm)
{
    <div class="card add-form">
        <div class="card-body">
            <input class="form-control form-control-lg mb-2" @bind="_newSiteName" placeholder="Site name" />
            <input class="form-control form-control-lg mb-2" @bind="_newSiteAddress" placeholder="Address" />
            <div class="d-flex gap-2">
                <button class="btn btn-success btn-lg flex-fill" @onclick="AddSite">Save</button>
                <button class="btn btn-secondary btn-lg" @onclick="() => _showAddForm = false">Cancel</button>
            </div>
        </div>
