@inherits LayoutComponentBase
@inject SyncService Sync

<div class="app-shell">
    <header class="app-header">
        <div class="sync-status @_statusClass">@_syncStatus</div>
    </header>

    <main class="app-content">
        @Body
    </main>
</div>

@code {
    private string _syncStatus = "";
    private string _statusClass = "";

    protected override void OnInitialized()
    {
        Sync.OnSyncStatusChanged += HandleSyncStatus;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await Sync.TrySyncAsync();
        }
    }

    private void HandleSyncStatus(string status)
    {
        _syncStatus = status;
        _statusClass = status switch
        {
            "Offline" => "status-offline",
            "Syncing..." => "status-syncing",
            _ when status.Contains("Synced") => "status-synced",
            _ => "status-default"
        };
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Sync.OnSyncStatusChanged -= HandleSyncStatus;
    }
}

using Microsoft.AspNetCore.Components.WebAssembly.Hosting;
using SiteInspector.Client.Services;

var builder = WebAssemblyHostBuilder.CreateDefault(args);

builder.Services.AddScoped(sp => new HttpClient { BaseAddress = new Uri(builder.HostEnvironment.BaseAddress) });
builder.Services.AddScoped<LocalStorageService>();
builder.Services.AddScoped<SyncService>();

await builder.Build().RunAsync();

