44.                             <button class="check-btn fail @(item.Result == CheckResult.Fail ? "selected" : "")"
45.                                     @onclick="() => SetResult(item, CheckResult.Fail)">✗</button>
46.                             <button class="check-btn na @(item.Result == CheckResult.NotApplicable ? "selected" : "")"
47.                                     @onclick="() => SetResult(item, CheckResult.NotApplicable)">N/A</button>
48.                         </div>
49.                     </div>
50.                 }
51.             }
52.         </div>
53.     }
54.     else if (_activeTab == "photos")
55.     {
56.         <div class="photo-section">
57.             <label class="btn btn-primary btn-lg w-100 mb-3">
58.                 📸 Take / Attach Photo
59.                 <InputFile OnChange="OnPhotoSelected" accept="image/*" capture="environment" style="display:none" />
60.             </label>
61. 
62.             @if (_inspection.Photos.Count == 0)
63.             {
64.                 <p class="text-muted">No photos attached yet.</p>
65.             }
66.             else
67.             {
68.                 <div class="photo-grid">
69.                     @foreach (var photo in _inspection.Photos.OrderByDescending(p => p.TakenAt))
70.                     {
