73.                             <input class="form-control mt-1" placeholder="Add caption..."
74.                                    value="@photo.Caption"
75.                                    @onchange="(e) => UpdateCaption(photo, e.Value?.ToString() ?? &quot;&quot;)" />
76.                         </div>
77.                     }
78.                 </div>
79.             }
80.         </div>
81.     }
82.     else if (_activeTab == "notes")
83.     {
84.         <div class="notes-section">
85.             <textarea class="form-control form-control-lg" rows="8"
86.                       placeholder="Add inspection notes, observations, or follow-up items..."
87.                       @bind="_inspection.Notes" @bind:after="SaveAsync"></textarea>
88.         </div>
89.     }
90. 
91.     <div class="inspection-footer">
92.         @if (_inspection.Status == InspectionStatus.InProgress)
93.         {
94.             <button class="btn btn-success btn-lg w-100" @onclick="CompleteInspection">
95.                 ✓ Complete Inspection
96.             </button>
97.         }
98.         else
99.         {
100.             <div class="alert alert-success text-center">
