107. @code {
108.     [Parameter] public string InspectionId { get; set; } = "";
109. 
110.     private Inspection? _inspection;
111.     private string _activeTab = "checklist";
112. 
113.     protected override async Task OnInitializedAsync()
114.     {
115.         _inspection = await Storage.GetInspectionAsync(InspectionId);
116.     }
117. 
118.     private async Task SetResult(ChecklistItem item, CheckResult result)
119.     {
120.         item.Result = result;
121.         await SaveAsync();
122.     }
123. 
124.     private string GetItemClass(ChecklistItem item) => item.Result switch
125.     {
126.         CheckResult.Pass => "item-pass",
127.         CheckResult.Fail => "item-fail",
128.         CheckResult.NotApplicable => "item-na",
129.         _ => ""
130.     };
131. 
132.     private async Task OnPhotoSelected(InputFileChangeEventArgs e)
133.     {
134.         if (_inspection is null) return;
135. 
136.         foreach (var file in e.GetMultipleFiles(5))
137.         {
138.             var buffer = new byte[file.Size];
139.             await file.OpenReadStream(maxAllowedSize: 10 * 1024 * 1024).ReadAsync(buffer);
140.             var base64 = Convert.ToBase64String(buffer);
141. 
142.             _inspection.Photos.Add(new InspectionPhoto
143.             {
144.                 FileName = file.Name,
145.                 Base64Data = base64
146.             });
147.         }
148. 
149.         await SaveAsync();
150.     }
151. 
152.     private async Task UpdateCaption(InspectionPhoto photo, string caption)
153.     {
154.         photo.Caption = caption;
155.         await SaveAsync();
156.     }
157. 
158.     private async Task CompleteInspection()
159.     {
160.         if (_inspection is null) return;
161.         _inspection.Status = InspectionStatus.Completed;
162.         await SaveAsync();
163.         await Sync.TrySyncAsync();
164.     }
165. 
166.     private async Task SaveAsync()
167.     {
168.         if (_inspection is null) return;
169.         _inspection.IsSynced = false;
170.         await Storage.SaveInspectionAsync(_inspection);
171.     }
172. 
173.     private void GoBack()
174.     {
175.         if (_inspection is not null)
176.             Nav.NavigateTo($"site/{_inspection.SiteId}");
177.         else
178.             Nav.NavigateTo("/");
179.     }
180. }
