 <PageTitle>Inspection</PageTitle>

 @if (_inspection is null)
 {
     <p class="loading">Loading...</p>
 }
 else
 {
     <div class="page-header">
         <button class="btn btn-outline-secondary" @onclick="GoBack">← Back</button>
         <h1>Inspection</h1>
     </div>

     <div class="inspection-tabs">
         <button class="tab-btn @(_activeTab == "checklist" ? "active" : "")" @onclick="() => _activeTab = &quot;checklist&quot;">
             ✓ Checklist
         </button>
         <button class="tab-btn @(_activeTab == "photos" ? "active" : "")" @onclick="() => _activeTab = &quot;photos&quot;">
             📷 Photos (@_inspection.Photos.Count)
         </button>
         <button class="tab-btn @(_activeTab == "notes" ? "active" : "")" @onclick="() => _activeTab = &quot;notes&quot;">
             📝 Notes
         </button>
     </div>

     @if (_activeTab == "checklist")
     {
         <div class="checklist">
             @foreach (var category in _inspection.ChecklistItems.GroupBy(c => c.Category))
             {
                 <h3 class="checklist-category">@category.Key</h3>
                 @foreach (var item in category)
                 {
                     <div class="checklist-item @GetItemClass(item)">
                         <div class="checklist-desc">@item.Description</div>
                         <div class="checklist-actions">
                             <button class="check-btn pass @(item.Result == CheckResult.Pass ? "selected" : "")"
                                     @onclick="() => SetResult(item, CheckResult.Pass)">✓</button>
                             <button class="check-btn fail @(item.Result == CheckResult.Fail ? "selected" : "")"
                                     @onclick="() => SetResult(item, CheckResult.Fail)">✗</button>
                             <button class="check-btn na @(item.Result == CheckResult.NotApplicable ? "selected" : "")"
                                     @onclick="() => SetResult(item, CheckResult.NotApplicable)">N/A</button>
                         </div>
                     </div>
                 }
             }
         </div>
     }
     else if (_activeTab == "photos")
     {
         <div class="photo-section">
             <label class="btn btn-primary btn-lg w-100 mb-3">
                 📸 Take / Attach Photo
                 <InputFile OnChange="OnPhotoSelected" accept="image/*" capture="environment" style="display:none" />
             </label>

             @if (_inspection.Photos.Count == 0)
             {
                 <p class="text-muted">No photos attached yet.</p>
             }
             else
             {
                 <div class="photo-grid">
                     @foreach (var photo in _inspection.Photos.OrderByDescending(p => p.TakenAt))
                     {
                         <div class="photo-card">
                             <img src="@($"data:image/jpeg;base64,{photo.Base64Data}")" alt="@photo.Caption" />
                             <input class="form-control mt-1" placeholder="Add caption..."
                                    value="@photo.Caption"
                                    @onchange="(e) => UpdateCaption(photo, e.Value?.ToString() ?? &quot;&quot;)" />
                         </div>
                     }
                 </div>
             }
         </div>
     }
     else if (_activeTab == "notes")
     {
         <div class="notes-section">
             <textarea class="form-control form-control-lg" rows="8"
                       placeholder="Add inspection notes, observations, or follow-up items..."
                       @bind="_inspection.Notes" @bind:after="SaveAsync"></textarea>
         </div>
     }

     <div class="inspection-footer">
         @if (_inspection.Status == InspectionStatus.InProgress)
         {
             <button class="btn btn-success btn-lg w-100" @onclick="CompleteInspection">
                 ✓ Complete Inspection
             </button>
         }
         else
         {
             <div class="alert alert-success text-center">
                 ✓ Inspection completed — @(_inspection.IsSynced ? "synced to server" : "waiting to sync")
             </div>
         }
     </div>
